// Shape the incoming payload into an Anthropic Messages request.
const body = ($input.first().json.body) || {};
const incoming = Array.isArray(body.messages) ? body.messages : [];

const system = "You are the AIverse assistant for NESR's internal AI learning site. Answer questions about AI concepts and the course material \u2014 neural networks, large language models, transformers, generative AI, prompting, RAG, agents, and AI ethics. Keep answers clear, concise, and beginner-friendly. If a question is unrelated to AI or the courses, gently steer the user back. Do not invent NESR-internal policies or data.";

const messages = incoming
  .filter(m => m && (m.role === 'user' || m.role === 'assistant') && typeof m.content === 'string')
  .map(m => ({ role: m.role, content: String(m.content).slice(0, 2000) }))
  .slice(-20);

// Anthropic requires the first message to be from the user (drop the greeting).
while (messages.length && messages[0].role !== 'user') messages.shift();

return [{ json: {
  model: 'claude-sonnet-5',
  max_tokens: 500,
  temperature: 0.3,
  system,
  messages
} }];

// Extract the assistant text from the Anthropic response \u2192 { reply }.
const d = $input.first().json;
const parts = Array.isArray(d?.content) ? d.content.map(c => c && c.text).filter(Boolean) : [];
const reply = parts.join('') || d?.reply || d?.output || "Sorry \u2014 I couldn't generate a reply. Please try again.";
return [{ json: { reply: String(reply).trim() } }];
